document.addEventListener('DOMContentLoaded',function(){function addPasswordToggle(input){if(!input||input.dataset.toggleAdded)return;input.dataset.toggleAdded='true';var wrapper=document.createElement('div');wrapper.style.cssText='display:inline-flex;align-items:center;gap:8px;';input.parentNode.insertBefore(wrapper,input);wrapper.appendChild(input);var btn=document.createElement('button');btn.type='button';btn.className='btn btn-light btn-sm';btn.style.cssText='line-height:1;padding:6px 10px;';btn.setAttribute('aria-label','Show or hide password');btn.innerHTML='👁️';btn.addEventListener('click',function(e){e.preventDefault();var show=input.type==='password';input.type=show?'text':'password';btn.innerHTML=show?'🙈':'👁️';btn.title=show?'Hide password':'Show password';});wrapper.appendChild(btn);}
document.querySelectorAll('input[type="password"]').forEach(addPasswordToggle);setTimeout(function(){var nav=document.querySelector('.main-header .navbar-nav.ml-auto')||document.querySelector('.main-header .navbar-nav:last-child');if(!nav||document.getElementById('explicit-logout-btn'))return;var item=document.createElement('li');item.className='nav-item';item.innerHTML='<a href="/admin/logout/" id="explicit-logout-btn" class="nav-link" '+'style="color:#dc2626 !important;font-weight:600;">'+'<i class="fas fa-sign-out-alt mr-1"></i> Logout</a>';nav.insertBefore(item,nav.firstChild);},300);});